import React, { useState, FormEvent } from "react";
import { sendMessage } from "../api/chat";

interface Message {
  role: "user" | "bot";
  text: string;
}

export const ChatBox: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState<string>("");
  const [loading, setLoading] = useState<boolean>(false);

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;
    const userMsg: Message = { role: "user", text: input };
    setMessages((prev) => [...prev, userMsg]);
    setLoading(true);
    try {
      const reply = await sendMessage(input);
      const botMsg: Message = { role: "bot", text: reply };
      setMessages((prev) => [...prev, botMsg]);
    } catch (err) {
      const errMsg: Message = { role: "bot", text: "Error contacting backend" };
      setMessages((prev) => [...prev, errMsg]);
    } finally {
      setLoading(false);
      setInput("");
    }
  };

  return (
    <div className="chat-box" style={{ maxWidth: "600px", margin: "0 auto" }}>
      <div className="messages" style={{ minHeight: "300px", border: "1px solid #ccc", padding: "1rem", overflowY: "auto" }}>
        {messages.map((msg, idx) => (
          <div key={idx} style={{ marginBottom: "0.5rem" }}>
            <strong>{msg.role === "user" ? "You" : "Bot"}:</strong> {msg.text}
          </div>
        ))}
        {loading && <div>Thinking...</div>}
      </div>
      <form onSubmit={handleSubmit} style={{ marginTop: "1rem", display: "flex" }}>
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Ask something..."
          disabled={loading}
          style={{ flexGrow: 1, padding: "0.5rem" }}
        />
        <button type="submit" disabled={loading} style={{ marginLeft: "0.5rem" }}>
          Send
        </button>
      </form>
    </div>
  );
};

