', 'frontend_chat_ts': 'export async function sendMessageStream(message: string, onToken: (t: string) => void): Promise<void> {
  const response = await fetch(import.meta.env.VITE_BACKEND_URL + "/chat/stream", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ message }),
  });
  const reader = response.body?.getReader();
  const decoder = new TextDecoder();
  while (reader) {
    const { value, done } = await reader.read();
    if (done) break;
    const chunk = decoder.decode(value);
    for (const line of chunk.split("\n")) {
      if (line.startsWith("data:")) {
        onToken(line.slice(5).trim());
      }
    }
  }
}
