', 'backend_auth_py': 'import os
import jwt
from datetime import datetime, timedelta
from fastapi import HTTPException, status

SECRET_KEY = os.getenv("JWT_SECRET", "supersecret")
ALGORITHM = "HS256"
ACCESS_TOKEN_EXPIRE_MINUTES = 30

def create_access_token(data: dict) -> str:
    to_encode = data.copy()
    expire = datetime.utcnow() + timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
    to_encode.update({"exp": expire})
    return jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)

def decode_token(token: str) -> dict:
    try:
        return jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
    except jwt.PyJWTError as exc:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Invalid token") from exc
', 'backend_router_py': 'from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
from .auth import decode_token, create_access_token
from .schemas import LoginRequest, TokenResponse

security = HTTPBearer()

@api_router.post("/login", response_model=TokenResponse)
async def login(req: LoginRequest):
    # In a real app verify against a DB; here we accept any non‑empty credentials
    if not req.username or not req.password:
        raise HTTPException(status_code=400, detail="Missing credentials")
    token = create_access_token({"sub": req.username})
    return TokenResponse(access_token=token)

def get_current_user(credentials: HTTPAuthorizationCredentials = Depends(security)):
    payload = decode_token(credentials.credentials)
    return payload.get("sub")

@api_router.post("/chat", response_model=ChatResponse, dependencies=[Depends(get_current_user)])
async def chat_endpoint(request: ChatRequest, user: str = Depends(get_current_user)):
    # user variable now holds the username from the token
    reply = await generate_reply(f"[{user}] {request.message}")
    return ChatResponse(reply=reply)
